<!-- 功能说明
管理端分类管理核心页面，支持一级分类与二级分类的新增、编辑、删除、排序，分类状态切换（启用 / 禁用），
核心对接分类管理相关接口，为产品管理提供分类数据支撑�� -->�


<template>
  <view class="category-manage-container">
    <!-- 页面头部 -->
    <view class="page-header">
      <text class="header-title">分类管理</text>
      <button class="add-btn" @click="showAddModal('first')">+ 新增一级分类</button>
    </view>

    <!-- 一级分类列表 -->
    <view class="first-category-list" v-if="firstCategoryList.length > 0">
      <view class="category-item first-category" v-for="(firstItem, firstIndex) in firstCategoryList" :key="firstItem.id">
        <!-- 一级分类信息 -->
        <view class="category-header">
          <view class="category-info">
            <image :src="firstItem.iconUrl || '/static/images/select.png'" class="category-icon"></image>
            <view class="category-name-status">
              <text class="category-name">{{firstItem.name}}</text>
              <text class="category-status" :class="firstItem.status === 1 ? 'status-on' : 'status-off'">
                {{firstItem.status === 1 ? '启用' : '禁用'}}
              </text>
            </view>
          </view>
          <view class="category-operation">
            <button class="oper-btn add-child-btn" @click="showAddModal('second', firstItem.id, firstIndex)">+ 新增子分类</button>
            <button class="oper-btn edit-btn" @click="showEditModal('first', firstItem, firstIndex)">编辑</button>
            <button 
              class="oper-btn status-btn" 
              @click="toggleCategoryStatus('first', firstItem.id, firstItem.status, firstIndex)"
            >
              {{firstItem.status === 1 ? '禁用' : '启用'}}
            </button>
            <button class="oper-btn delete-btn" @click="deleteCategory('first', firstItem.id, firstIndex)">删除</button>
          </view>
        </view>

        <!-- 二级分类列表 -->
        <view class="second-category-list" v-if="firstItem.children && firstItem.children.length > 0">
          <view class="category-item second-category" v-for="(secondItem, secondIndex) in firstItem.children" :key="secondItem.id">
            <view class="category-info second-info">
                <image :src="secondItem.iconUrl || '/static/images/select.png'" class="category-icon second-icon"></image>
              <view class="category-name-status">
                <text class="category-name">{{secondItem.name}}</text>
                <text class="category-status" :class="secondItem.status === 1 ? 'status-on' : 'status-off'">
                  {{secondItem.status === 1 ? '启用' : '禁用'}}
                </text>
              </view>
            </view>
            <view class="category-operation">
              <button class="oper-btn edit-btn" @click="showEditModal('second', secondItem, firstIndex, secondIndex)">编辑</button>
              <button 
                class="oper-btn status-btn" 
                @click="toggleCategoryStatus('second', secondItem.id, secondItem.status, firstIndex, secondIndex)"
              >
                {{secondItem.status === 1 ? '禁用' : '启用'}}
              </button>
              <button class="oper-btn delete-btn" @click="deleteCategory('second', secondItem.id, firstIndex, secondIndex)">删除</button>
            </view>
          </view>
        </view>
      </view>
    </view>

    <!-- 空列表状态 -->
    <view class="empty-list" v-else>
      <image src="/static/images/select.png" class="empty-img"></image>
      <text class="empty-text">暂无分类数据，点击右上角新增一级分类</text>
    </view>

    <!-- 新增/编辑分类弹窗 -->
    <uni-modal 
      :title="isEditMode ? (categoryLevel === 'first' ? '编辑一级分类' : '编辑二级分类') : (categoryLevel === 'first' ? '新增一级分类' : '新增二级分类')" 
      :visible="modalVisible" 
      width="90%"
      @confirm="confirmSubmit"
      @cancel="hideModal"
    >
      <view class="category-form">
        <!-- 分类名称 -->
        <view class="form-item">
          <text class="form-label required">分类名称：</text>
          <input 
            class="form-input" 
            v-model="formData.name" 
            placeholder="请输入分类名称"
            maxlength="20"
          ></input>
        </view>

        <!-- 分类图标（仅一级分类显示） -->
        <view class="form-item" v-if="categoryLevel === 'first'">
          <text class="form-label">分类图标：</text>
          <view class="upload-container">
            <view class="upload-preview" v-if="formData.iconUrl">
              <image :src="formData.iconUrl" mode="aspectFill" class="preview-img"></image>
              <image src="/static/images/icon-close.png" class="close-icon" @click="clearIcon"></image>
            </view>
            <view class="upload-btn" @click="chooseIcon" v-else>
              <image src="/static/images/upload.png" class="upload-icon"></image>
              <text class="upload-text">点击上传图标</text>
            </view>
          </view>
          <text class="form-hint">建议尺寸：80*80px，支持jpg/png格式，单张不超过2MB</text>
        </view>

        <!-- 父分类（仅二级分类显示） -->
        <view class="form-item" v-if="categoryLevel === 'second'">
          <text class="form-label required">父分类：</text>
          <picker 
            :range="firstCategoryList"
            :range-key="'name'"
            :value="selectedParentIndex"
            class="parent-picker"
            @change="handleParentPickerChange"
          >
            <view class="picker-text">{{firstCategoryList[selectedParentIndex]?.name || '请选择父分类'}}</view>
          </picker>
        </view>

        <!-- 排序 -->
        <view class="form-item">
          <text class="form-label">排序：</text>
          <input 
            class="form-input" 
            v-model.number="formData.sort" 
            placeholder="数字越小越靠前，默认0"
            type="number"
          ></input>
        </view>
      </view>
    </uni-modal>
  </view>
</template>

<script setup>
import { ref } from 'vue';
import { onLoad, onShow } from '@dcloudio/uni-app';
import { useUserStore } from '@/store/modules/userStore';
import request, { upload } from '@/utils/request';

// 状态管理
const userStore = useUserStore();

// 页面数据
const firstCategoryList = ref([]); // 一级分类列表（含二级子分类）
const modalVisible = ref(false); // 新增/编辑弹窗
const isEditMode = ref(false); // 是否编辑模式
const categoryLevel = ref('first'); // 分类级别：first/second
const selectedParentIndex = ref(0); // 选中的父分类索引
const formData = ref({
  id: '', // 分类ID（编辑模式）
  name: '', // 分类名称
  iconUrl: '', // 分类图标（仅一级）
  parentId: '', // 父分类ID（仅二级）
  sort: 0, // 排序
  status: 1 // 状态：1-启用，0-禁用
});
// 编辑时的索引
const editIndex = ref({
  first: -1, // 一级分类索引
  second: -1 // 二级分类索引
});

// 页面加载时获取分类列表
onLoad(() => {
  if (!userStore.token || userStore.userInfo.role !== 'ADMIN') {
    uni.navigateTo({ url: '/pages/admin/login' });
    return;
  }
  getCategoryList();
});

onShow(() => {
  getCategoryList();
});

// 接口请求：获取分类列表（树形结构）
const getCategoryList = async () => {
  uni.showLoading({ title: '加载中' });
  try {
    const res = await request({
      url: '/api/category/tree',
      method: 'GET'
    });
    if (res.success) {
      firstCategoryList.value = res.data;
    }
  } catch (error) {
    uni.showToast({ title: '分类列表加载失败', icon: 'none' });
  } finally {
    uni.hideLoading();
  }
};

// 显示新增弹窗
const showAddModal = (level, parentId = '', firstIndex = -1) => {
  isEditMode.value = false;
  categoryLevel.value = level;
  formData.value = {
    id: '',
    name: '',
    iconUrl: '',
    parentId: parentId,
    sort: 0,
    status: 1
  };
  selectedParentIndex.value = firstIndex !== -1 ? firstIndex : 0;
  modalVisible.value = true;
};

// 显示编辑弹窗
const showEditModal = (level, item, firstIndex, secondIndex = -1) => {
  isEditMode.value = true;
  categoryLevel.value = level;
  editIndex.value = { first: firstIndex, second: secondIndex };
  formData.value = { ...item };
  // 二级分类设置父分类索引
  if (level === 'second') {
    const parentIndex = firstCategoryList.value.findIndex(f => f.id === item.parentId);
    selectedParentIndex.value = parentIndex !== -1 ? parentIndex : 0;
  }
  modalVisible.value = true;
};

// 处理父分类选择器变化
const handleParentPickerChange = (e) => {
  selectedParentIndex.value = e.detail.value;
};

// 隐藏弹窗
const hideModal = () => {
  modalVisible.value = false;
  formData.value.iconUrl = ''; // 清空图标预览
};

// 选择并上传图标
const chooseIcon = () => {
  uni.chooseImage({
    count: 1,
    sizeType: ['compressed'],
    sourceType: ['album', 'camera'],
    success: (res) => {
      const tempFilePath = res.tempFilePaths[0];
      uploadIcon(tempFilePath);
    }
  });
};

// 上传图标接口
const uploadIcon = async (filePath) => {
  uni.showLoading({ title: '图标上传中' });
  try {
    const res = await upload({
      url: '/api/upload/image',
      filePath: filePath,
      name: 'file',
      formData: {
        type: 'category' // 图片类型标识
      }
    });
    if (res.success) {
      formData.value.iconUrl = res.data;
      uni.hideLoading();
    } else {
      uni.showToast({ title: res.message || '图标上传失败', icon: 'none' });
      uni.hideLoading();
    }
  } catch (error) {
    console.error('上传图片失败:', error);
  }
};

// 清空图标
const clearIcon = () => {
  formData.value.iconUrl = '';
};

// 提交新增/编辑
const confirmSubmit = async () => {
  // 表单校验
  if (!formData.value.name.trim()) {
    uni.showToast({ title: '请输入分类名称', icon: 'none' });
    return;
  }
  if (categoryLevel.value === 'second' && !firstCategoryList.value[selectedParentIndex.value]?.id) {
    uni.showToast({ title: '请选择父分类', icon: 'none' });
    return;
  }

  // 处理二级分类父ID
  if (categoryLevel.value === 'second') {
    formData.value.parentId = firstCategoryList.value[selectedParentIndex.value].id;
  }

  uni.showLoading({ title: '提交中' });
  try {
    let res;
    if (isEditMode.value) {
      // 编辑分类
      res = await request({
        url: `/api/admin/category/${formData.value.id}`,
        method: 'PUT',
        data: {
          name: formData.value.name,
          iconUrl: formData.value.iconUrl,
          parentId: formData.value.parentId,
          sort: formData.value.sort,
          status: formData.value.status
        }
      });
    } else {
      // 新增分类
      res = await request({
        url: '/api/admin/category/add',
        method: 'POST',
        data: formData.value
      });
    }

    if (res.success) {
      uni.showToast({ title: isEditMode.value ? '编辑成功' : '新增成功' });
      hideModal();
      getCategoryList();
    } else {
      uni.showToast({ title: res.message || (isEditMode.value ? '编辑失败' : '新增失败'), icon: 'none' });
    }
  } catch (error) {
    uni.showToast({ title: '网络异常，操作失败', icon: 'none' });
  } finally {
    uni.hideLoading();
  }
};

// 切换分类状态（启用/禁用）
const toggleCategoryStatus = async (level, categoryId, status, firstIndex, secondIndex = -1) => {
  const newStatus = status === 1 ? 0 : 1;
  const statusText = newStatus === 1 ? '启用' : '禁用';

  uni.showModal({
    title: '提示',
    content: `确定要${statusText}该分类吗？`,
    success: async (res) => {
      if (res.confirm) {
        try {
          const res = await request({
            url: `/api/admin/category/${categoryId}/status`,
            method: 'PUT',
            params: { status: newStatus }
          });
          if (res.success) {
            uni.showToast({ title: `${statusText}成功` });
            // 更新本地数据
            if (level === 'first') {
              firstCategoryList.value[firstIndex].status = newStatus;
            } else {
              firstCategoryList.value[firstIndex].children[secondIndex].status = newStatus;
            }
          } else {
            uni.showToast({ title: `${statusText}失败`, icon: 'none' });
          }
        } catch (error) {
          uni.showToast({ title: '网络异常，操作失败', icon: 'none' });
        }
      }
    }
  });
};

// 删除分类
const deleteCategory = async (level, categoryId, firstIndex, secondIndex = -1) => {
  // 一级分类删除前检查是否有子分类
  if (level === 'first' && firstCategoryList.value[firstIndex].children && firstCategoryList.value[firstIndex].children.length > 0) {
    uni.showToast({ title: '该分类下有子分类，无法删除', icon: 'none' });
    return;
  }

  uni.showModal({
    title: '警告',
    content: '确定要删除该分类吗？删除后不可恢复！',
    confirmColor: '#F53F3F',
    success: async (res) => {
      if (res.confirm) {
        try {
          const res = await request({
            url: `/api/admin/category/${categoryId}`,
            method: 'DELETE'
          });
          if (res.success) {
            uni.showToast({ title: '删除成功' });
            // 更新本地数据
            if (level === 'first') {
              firstCategoryList.value.splice(firstIndex, 1);
            } else {
              firstCategoryList.value[firstIndex].children.splice(secondIndex, 1);
            }
          } else {
            uni.showToast({ title: '删除失败', icon: 'none' });
          }
        } catch (error) {
          uni.showToast({ title: '网络异常，删除失败', icon: 'none' });
        }
      }
    }
  });
};
</script>

